('spanish:8-2-social-media-and-online-safety:mcq:fe0e797f', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "Careful — ‘la red’ on its own (as in ‘la red social’) means…", "options": ["network", "the colour red", "a red warning sign", "a type of red fruit grown in Spain"]}'::jsonb, '{"answer": 0, "explain": "False friend! ‘red’ = network, not the colour red. The obvious guess is the trap."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:mcq:3d1c62b0', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'mcq', 'mcq', 1, '{"question": "Which sentence gives GOOD online safety advice?", "options": ["No se debe compartir datos personales", "Se debe compartir tu contraseña con todos tus amigos", "Se debe compartir datos personales sin cuidado", "No hay que proteger tu contraseña nunca"]}'::jsonb, '{"answer": 0, "explain": "‘no se debe compartir datos personales’ is sound advice; the rest recommend unsafe behaviour."}'::jsonb),
